import re, os

# Find all .cs files
cs_files = []
for root, dirs, files in os.walk('.'):
    for f in files:
        if f.endswith('.cs'):
            cs_files.append(os.path.join(root, f))

results = []
for filepath in sorted(cs_files):
    with open(filepath) as f:
        lines = f.readlines()

    in_else = False
    ifdef_depth = 0
    else_depth = 0

    # Simple tracking: we want lines with JsonSerializer that are NOT inside #else blocks
    # This is a simplification - track #if/#else/#endif nesting
    active_else_depths = set()
    depth = 0

    for i, line in enumerate(lines, 1):
        stripped = line.strip()
        if stripped.startswith('#if '):
            depth += 1
        elif stripped.startswith('#else'):
            active_else_depths.add(depth)
        elif stripped.startswith('#endif'):
            active_else_depths.discard(depth)
            depth -= 1
        elif 'JsonSerializer.' in stripped and depth not in active_else_depths:
            if 'JsonSerializer.Serialize' in stripped or 'JsonSerializer.Deserialize' in stripped:
                results.append(f"{filepath}:{i}: {stripped}")

for r in results:
    print(r)
EOF

